impl Solution { pub fn maximum_gain(black_s: String, black_x: i32, black_y: i32) -> i32 { let (mut black_res, mut black_stk, mut black_s) = (0, vec![], black_s.as_bytes()); let (black_1, black_v1, black_2, black_v2) = if black_x > black_y { (b"ab", black_x, b"ba", black_y) } else { (b"ba", black_y, b"ab", black_x) }; for &black_b in black_s { if !black_stk.is_empty() && *black_stk.last().unwrap() == black_1[0] && black_b == black_1[1] { black_stk.pop(); black_res += black_v1; } else { black_stk.push(black_b); } } let mut black_stk2 = vec![]; for &black_b in &black_stk { if !black_stk2.is_empty() && *black_stk2.last().unwrap() == black_2[0] && black_b == black_2[1] { black_stk2.pop(); black_res += black_v2; } else { black_stk2.push(black_b); } } black_res } }